%[text] # 例7.1 （ゾーン符号化）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example07_01"; % mfilename

imgname = "msipimg02";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');

figure(1) %[output:9727ced8]
subplot(1,2,1) %[output:9727ced8]
imshow(X) %[output:9727ced8]
title('原画像') %[output:9727ced8]
imwrite(X,fullfile(resfolder,"fig07-01a.png"))
%%
%[text] ## ブロックDCT
Z = zeros(8);
K = 3 %[output:5abf4f65]
for iCols = 1:8
    for iRows = 1:8
        if iCols + iRows - 2 < 2
            Z(iRows,iCols) = 1;
        end
    end
end
Z %[output:0090b692]
Y = blockproc(X,[8 8],@(x) idct2(Z.*dct2(x.data)));

subplot(1,2,2) %[output:374473a7]
imshow(Y) %[output:374473a7]
title("ブロックDCT (PSNR:"+psnr(X,Y)+" dB") %[output:374473a7]
imwrite(Y,fullfile(resfolder,"fig07-01b.png"))
%%
